codeExample1.code:
#include <stdio.h>

int main() {
    int score = 85;
    char grade;

    if (score < 0 || score > 100) {
        printf("Invalid score entered.\n");
        return 1;
    }

    if (score >= 90) {
        grade = 'A';
    } else if (score >= 80) {
        grade = 'B';
    } else if (score >= 70) {
        grade = 'C';
    } else if (score >= 60) {
        grade = 'D';
    } else {
        grade = 'F';
    }

    printf("Score: %d, Assigned Grade: %c\n", score, grade);
    return 0;
}

codeExample2.code:
#include <stdio.h>

int main() {
    char operator = '*';
    double num1 = 12.0;
    double num2 = 4.0;
    double result;

    switch (operator) {
        case '+':
            result = num1 + num2;
            break;
        case '-':
            result = num1 - num2;
            break;
        case '*':
            result = num1 * num2;
            break;
        case '/':
            if (num2 != 0.0) {
                result = num1 / num2;
            } else {
                printf("Error: Division by zero is undefined.\n");
                return 1;
            }
            break;
        default:
            printf("Error: Unsupported mathematical operator '%c'.\n", operator);
            return 1;
    }

    printf("Result: %.2f %c %.2f = %.2f\n", num1, operator, num2, result);
    return 0;
}

